#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <omp.h>

#define fp double
#define NUMBER_PAR_PER_BOX 100
#define NUMBER_THREADS 128
#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct {
    fp x, y, z;
} THREE_VECTOR;

typedef struct {
    fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str {
    int x, y, z;
    int number;
    long offset;
} nei_str;

typedef struct box_str {
    int x, y, z;
    int number;
    long offset;
    int nn;
    nei_str nei[26];
} box_str;

typedef struct par_str {
    fp alpha;
} par_str;

typedef struct dim_str {
    int cur_arg;
    int arch_arg;
    int cores_arg;
    int boxes1d_arg;
    long number_boxes;
    long box_mem;
    long space_elem;
    long space_mem;
    long space_mem2;
} dim_str;

static inline long long get_time() {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000) + tv.tv_usec;
}

static inline int isInteger(char *str) {
    if (*str == '\0') return 0;
    for (; *str != '\0'; str++) {
        if (*str < 48 || *str > 57) return 0;
    }
    return 1;
}

void kernel_cpu(par_str par_cpu,
                dim_str dim_cpu,
                box_str* box_cpu,
                FOUR_VECTOR* rv_cpu,
                fp* qv_cpu,
                FOUR_VECTOR* fv_cpu) {

    long long time0, time1, time2, time3, time4, time5, time6;
    time0 = get_time();

    int number_boxes = dim_cpu.number_boxes;
    fp alpha = par_cpu.alpha;
    fp a2 = 2.0 * alpha * alpha;

    time1 = get_time();

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        int nthreads = omp_get_num_threads();

        FOUR_VECTOR rA_shared[NUMBER_PAR_PER_BOX];
        FOUR_VECTOR rB_shared[NUMBER_PAR_PER_BOX];
        double qB_shared[NUMBER_PAR_PER_BOX];

        #pragma omp for schedule(static, 1)
        for (int bx = 0; bx < number_boxes; bx++) {
            int first_i = box_cpu[bx].offset;
            FOUR_VECTOR* rA = &rv_cpu[first_i];
            FOUR_VECTOR* fA = &fv_cpu[first_i];

            for (int wtx = tid; wtx < NUMBER_PAR_PER_BOX; wtx += nthreads) {
                rA_shared[wtx] = rA[wtx];
            }
            #pragma omp barrier

            for (int k = 0; k < (1 + box_cpu[bx].nn); k++) {
                int pointer;
                if (k == 0) {
                    pointer = bx;
                } else {
                    pointer = box_cpu[bx].nei[k-1].number;
                }

                int first_j = box_cpu[pointer].offset;
                FOUR_VECTOR* rB = &rv_cpu[first_j];
                fp* qB = &qv_cpu[first_j];

                for (int wtx = tid; wtx < NUMBER_PAR_PER_BOX; wtx += nthreads) {
                    rB_shared[wtx] = rB[wtx];
                    qB_shared[wtx] = qB[wtx];
                }
                #pragma omp barrier

                for (int wtx = tid; wtx < NUMBER_PAR_PER_BOX; wtx += nthreads) {
                    for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
                        fp r2 = (fp)rA_shared[wtx].v + (fp)rB_shared[j].v - DOT(( THREE_VECTOR )rA_shared[wtx], ( THREE_VECTOR )rB_shared[j]);
                        fp u2 = a2 * r2;
                        fp vij = exp(-u2);
                        fp fs = 2 * vij;

                        THREE_VECTOR d;
                        d.x = (fp)rA_shared[wtx].x - (fp)rB_shared[j].x;
                        d.y = (fp)rA_shared[wtx].y - (fp)rB_shared[j].y;
                        d.z = (fp)rA_shared[wtx].z - (fp)rB_shared[j].z;

                        fp fxij = fs * d.x;
                        fp fyij = fs * d.y;
                        fp fzij = fs * d.z;

                        fA[wtx].v += (double)((fp)qB_shared[j] * vij);
                        fA[wtx].x += (double)((fp)qB_shared[j] * fxij);
                        fA[wtx].y += (double)((fp)qB_shared[j] * fyij);
                        fA[wtx].z += (double)((fp)qB_shared[j] * fzij);
                    }
                }
                #pragma omp barrier
            }
        }
    }

    time2 = get_time();

    printf("Time spent in different stages of CPU KERNEL:\n");
    printf("%15.12f s, %15.12f % : CPU: INIT\n", (float)(time1 - time0) / 1000000, (float)(time1 - time0) / (float)(time2 - time0) * 100);
    printf("%15.12f s, %15.12f % : CPU: KERNEL\n", (float)(time2 - time1) / 1000000, (float)(time2 - time1) / (float)(time2 - time0) * 100);
    printf("Total time:\n");
    printf("%.12f s\n", (float)(time2 - time0) / 1000000);
}

void kernel_gpu_cuda_wrapper(par_str par_cpu,
                             dim_str dim_cpu,
                             box_str* box_cpu,
                             FOUR_VECTOR* rv_cpu,
                             fp* qv_cpu,
                             FOUR_VECTOR* fv_cpu) {
    kernel_cpu(par_cpu, dim_cpu, box_cpu, rv_cpu, qv_cpu, fv_cpu);
}

int main(int argc, char *argv[]) {
    printf("thread block size of kernel = %d \n", NUMBER_THREADS);

    long long time0 = get_time();
    long long time1, time2, time3, time4, time5, time6, time7;
    int i, j, k, l, m, n;

    par_str par_cpu;
    dim_str dim_cpu;
    box_str* box_cpu;
    FOUR_VECTOR* rv_cpu;
    fp* qv_cpu;
    FOUR_VECTOR* fv_cpu;
    int nh;

    time1 = get_time();

    dim_cpu.cores_arg = 1;
    dim_cpu.boxes1d_arg = 1;

    for (dim_cpu.cur_arg = 1; dim_cpu.cur_arg < argc; dim_cpu.cur_arg++) {
        if (strcmp(argv[dim_cpu.cur_arg], "-cores") == 0) {
            if (argc >= dim_cpu.cur_arg + 1) {
                if (isInteger(argv[dim_cpu.cur_arg + 1]) == 1) {
                    dim_cpu.cores_arg = atoi(argv[dim_cpu.cur_arg + 1]);
                    if (dim_cpu.cores_arg < 0) {
                        printf("ERROR: Wrong value to -cores parameter, cannot be <=0\n");
                        return 0;
                    }
                    dim_cpu.cur_arg = dim_cpu.cur_arg + 1;
                } else {
                    printf("ERROR: Value to -cores parameter in not a number\n");
                    return 0;
                }
            } else {
                printf("ERROR: Missing value to -cores parameter\n");
                return 0;
            }
        } else if (strcmp(argv[dim_cpu.cur_arg], "-boxes1d") == 0) {
            if (argc >= dim_cpu.cur_arg + 1) {
                if (isInteger(argv[dim_cpu.cur_arg + 1]) == 1) {
                    dim_cpu.boxes1d_arg = atoi(argv[dim_cpu.cur_arg + 1]);
                    if (dim_cpu.boxes1d_arg < 0) {
                        printf("ERROR: Wrong value to -boxes1d parameter, cannot be <=0\n");
                        return 0;
                    }
                    dim_cpu.cur_arg = dim_cpu.cur_arg + 1;
                } else {
                    printf("ERROR: Value to -boxes1d parameter in not a number\n");
                    return 0;
                }
            } else {
                printf("ERROR: Missing value to -boxes1d parameter\n");
                return 0;
            }
        } else {
            printf("ERROR: Unknown parameter\n");
            return 0;
        }
    }

    printf("Configuration used: cores = %d, boxes1d = %d\n", dim_cpu.cores_arg, dim_cpu.boxes1d_arg);
    time2 = get_time();

    par_cpu.alpha = 0.5;
    time3 = get_time();

    dim_cpu.number_boxes = dim_cpu.boxes1d_arg * dim_cpu.boxes1d_arg * dim_cpu.boxes1d_arg;
    dim_cpu.space_elem = dim_cpu.number_boxes * NUMBER_PAR_PER_BOX;
    dim_cpu.space_mem = dim_cpu.space_elem * sizeof(FOUR_VECTOR);
    dim_cpu.space_mem2 = dim_cpu.space_elem * sizeof(fp);
    dim_cpu.box_mem = dim_cpu.number_boxes * sizeof(box_str);
    time4 = get_time();

    box_cpu = (box_str*)malloc(dim_cpu.box_mem);
    nh = 0;

    for (i = 0; i < dim_cpu.boxes1d_arg; i++) {
        for (j = 0; j < dim_cpu.boxes1d_arg; j++) {
            for (k = 0; k < dim_cpu.boxes1d_arg; k++) {
                box_cpu[nh].x = k;
                box_cpu[nh].y = j;
                box_cpu[nh].z = i;
                box_cpu[nh].number = nh;
                box_cpu[nh].offset = nh * NUMBER_PAR_PER_BOX;
                box_cpu[nh].nn = 0;

                for (l = -1; l < 2; l++) {
                    for (m = -1; m < 2; m++) {
                        for (n = -1; n < 2; n++) {
                            if (((i + l) >= 0 && (j + m) >= 0 && (k + n) >= 0) &&
                                ((i + l) < dim_cpu.boxes1d_arg && (j + m) < dim_cpu.boxes1d_arg && (k + n) < dim_cpu.boxes1d_arg) &&
                                (l == 0 && m == 0 && n == 0) == false) {

                                box_cpu[nh].nei[box_cpu[nh].nn].x = (k + n);
                                box_cpu[nh].nei[box_cpu[nh].nn].y = (j + m);
                                box_cpu[nh].nei[box_cpu[nh].nn].z = (i + l);
                                box_cpu[nh].nei[box_cpu[nh].nn].number = (box_cpu[nh].nei[box_cpu[nh].nn].z * dim_cpu.boxes1d_arg * dim_cpu.boxes1d_arg) +
                                                                         (box_cpu[nh].nei[box_cpu[nh].nn].y * dim_cpu.boxes1d_arg) +
                                                                         box_cpu[nh].nei[box_cpu[nh].nn].x;
                                box_cpu[nh].nei[box_cpu[nh].nn].offset = box_cpu[nh].nei[box_cpu[nh].nn].number * NUMBER_PAR_PER_BOX;
                                box_cpu[nh].nn = box_cpu[nh].nn + 1;
                            }
                        }
                    }
                }
                nh = nh + 1;
            }
        }
    }

    srand(time(NULL));
    rv_cpu = (FOUR_VECTOR*)malloc(dim_cpu.space_mem);
    for (i = 0; i < dim_cpu.space_elem; i++) {
        rv_cpu[i].v = (rand() % 10 + 1) / 10.0;
        rv_cpu[i].x = (rand() % 10 + 1) / 10.0;
        rv_cpu[i].y = (rand() % 10 + 1) / 10.0;
        rv_cpu[i].z = (rand() % 10 + 1) / 10.0;
    }

    qv_cpu = (fp*)malloc(dim_cpu.space_mem2);
    for (i = 0; i < dim_cpu.space_elem; i++) {
        qv_cpu[i] = (rand() % 10 + 1) / 10.0;
    }

    fv_cpu = (FOUR_VECTOR*)malloc(dim_cpu.space_mem);
    for (i = 0; i < dim_cpu.space_elem; i++) {
        fv_cpu[i].v = 0;
        fv_cpu[i].x = 0;
        fv_cpu[i].y = 0;
        fv_cpu[i].z = 0;
    }
    time5 = get_time();

    kernel_gpu_cuda_wrapper(par_cpu, dim_cpu, box_cpu, rv_cpu, qv_cpu, fv_cpu);
    time6 = get_time();

#ifdef OUTPUT
    FILE *fptr;
    fptr = fopen("result.txt", "w");
    for (i = 0; i < dim_cpu.space_elem; i++) {
        fprintf(fptr, "%f, %f, %f, %f\n", fv_cpu[i].v, fv_cpu[i].x, fv_cpu[i].y, fv_cpu[i].z);
    }
    fclose(fptr);
#endif

    free(rv_cpu);
    free(qv_cpu);
    free(fv_cpu);
    free(box_cpu);
    time7 = get_time();

    return 0;
}
